"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[836],{1342:e=>{e.exports=JSON.parse('{"functions":[],"properties":[{"name":"ControllerType","desc":"Passed as `DefineConfig.Type`. `Relative` sizes dynamically toward `RecommendedVoxelSize`\\nand splits multi-part Shatter calls across the Workers Actor pool; `Absolute` uses a fixed\\n`VoxelSize` and never threads.","lua_type":"{Relative: \\"Relative\\", Absolute: \\"Absolute\\"}","source":{"line":20,"path":"src/Enums/init.luau"}},{"name":"RuntimeType","desc":"Passed as `DefineConfig.RuntimeType`. `Instant` (default) runs every `Shatter` call the\\nmoment it\'s called; `Timeline` queues calls until `Controller:Start()` flushes them in order.","lua_type":"{Instant: \\"Instant\\", Timeline: \\"Timeline\\"}","source":{"line":27,"path":"src/Enums/init.luau"}},{"name":"HitboxType","desc":"Passed as `HitboxConfig.HitboxType`. `Partial` (default) slices whatever the hitbox finds;\\n`Whole` returns parts the hitbox fully contains untouched, with no slicing.","lua_type":"{Whole: \\"Whole\\", Partial: \\"Partial\\"}","source":{"line":34,"path":"src/Enums/init.luau"}},{"name":"QueryType","desc":"Passed as `HitboxConfig.QueryType`. Mirrors Roblox\'s own spatial query kinds. `Box`/`Region`\\nrun through the Octree + an exact box/AABB test, `Sphere` through the Octree + a distance\\ntest, and `Raycast` casts directly through the engine (single closest hit - see the README\'s\\nRaycast caveat).","lua_type":"{Raycast: \\"Raycast\\", Box: \\"Box\\", Sphere: \\"Sphere\\", Region: \\"Region\\"}","source":{"line":43,"path":"src/Enums/init.luau"}},{"name":"Effects","desc":"Keys into `ShatterConfig.Effects`. `Explode = {Radius: number}` pushes the voxel outward\\nfrom the Shatter origin; `Anchored = boolean` sets the produced part\'s `Anchored` directly.","lua_type":"{Explode: \\"Explode\\", Anchored: \\"Anchored\\"}","source":{"line":50,"path":"src/Enums/init.luau"}},{"name":"Cleanup","desc":"Passed as `ShatterConfig.Cleanup`, or to `Voxel:Cleanup` directly. `Destroy` is instant;\\n`Fade` tweens `Transparency` to 1 then destroys; `Rebuild` tweens the voxel\'s `CFrame` back\\nto `OriginalCFrame` and never destroys it.","lua_type":"{Rebuild: \\"Rebuild\\", Fade: \\"Fade\\", Destroy: \\"Destroy\\"}","source":{"line":58,"path":"src/Enums/init.luau"}},{"name":"Event","desc":"Passed to `PendingResult:Next`. `NewVoxel` fires once, right after voxelization/Effects;\\n`Destroyed` fires once every `Partial` voxel from that call has actually been destroyed by\\nCleanup (never fires if `Cleanup` was `Rebuild` or unset).","lua_type":"{NewVoxel: \\"NewVoxel\\", Destroyed: \\"Destroyed\\"}","source":{"line":66,"path":"src/Enums/init.luau"}}],"types":[],"name":"Enums","desc":"Every string-enum Facet\'s config and Result objects use. Each one is also re-exported as a\\ntype off the top-level `Facet` module (`Facet.ControllerType`, `Facet.RuntimeType`, etc.), so\\nyou don\'t need to reach into `Facet.Enums` just to annotate a variable.","source":{"line":11,"path":"src/Enums/init.luau"}}')}}]);